transforms.code:
out = []
for v in (value or []):
	v = v or {}
	vnum = v.get('VersionNumber', 0)
	name = v.get('Name') or ''
	if v.get('DeprecatedAt'):
		status = 'Deprecated'
	elif v.get('PublishedAt'):
		status = 'Published'
	else:
		status = 'Draft'
	out.append({'label': 'v' + str(vnum) + ' - ' + name + ' (' + status + ')', 'value': v.get('Id')})
return out

steps = BlueRidge.Common.Util.extractQualifiedValues(value) or []
if len(steps) == 0:
	return []
state = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.state) or {}
editDraft = state.get('editDraft') or {}
status = editDraft.get('status') or ''
if status == 'Draft':
	mode = 'draft'
elif status == 'Deprecated':
	mode = 'deprecated'
else:
	mode = 'published'
opTypes = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.opTypes) or []
total = len(steps)
out = []
for i, s in enumerate(steps):
	s = s or {}
	out.append({'rowIndex': i, 'step': dict(s), 'mode': mode, 'stepCount': total, 'opTypes': opTypes})
return out

customMethods.script:
itemId = self.view.params.value
self.view.custom.activeVersionId = None
self.view.custom.state = {"selected": self._emptyRoute(), "editDraft": self._emptyRoute()}
if not itemId:
	return
defaultId = BlueRidge.Parts.RouteTemplate.getDefaultVersionId(itemId)
if defaultId:
	self.view.custom.activeVersionId = defaultId

routeId = self.view.custom.activeVersionId
if not routeId:
	self.view.custom.state = {"selected": self._emptyRoute(), "editDraft": self._emptyRoute()}
	return
bundle = self._bundleFor(routeId)
self.view.custom.state = {"selected": bundle, "editDraft": self._cloneBundle(bundle)}

return {
	"id": None, "versionNumber": None, "name": "",
	"effectiveFromDisplay": "",
	"publishedAt": None, "deprecatedAt": None,
	"status": None, "steps": [],
}

header = BlueRidge.Parts.RouteTemplate.getHeader(routeId)
if not header:
	return self._emptyRoute()
steps = BlueRidge.Parts.RouteTemplate.getSteps(routeId) or []
if header.get("DeprecatedAt"):
	status = "Deprecated"
elif header.get("PublishedAt"):
	status = "Published"
else:
	status = "Draft"
return {
	"id": header.get("Id"),
	"versionNumber": header.get("VersionNumber"),
	"name": header.get("Name") or "",
	"effectiveFromDisplay": str(header.get("EffectiveFrom") or "")[:10],
	"publishedAt": str(header.get("PublishedAt") or "") or None,
	"deprecatedAt": str(header.get("DeprecatedAt") or "") or None,
	"status": status,
	"steps": [dict(s) for s in steps],
}

itemId = self.view.params.value
if not itemId:
	return
existing = BlueRidge.Parts.RouteTemplate.listVersions(itemId, True) or []
if existing:
	parentId = self.view.custom.activeVersionId or existing[0].get("Id")
	result = BlueRidge.Parts.RouteTemplate.createNewVersion(parentId)
else:
	result = BlueRidge.Parts.RouteTemplate.createInitial(itemId)
BlueRidge.Common.Ui.notifyResult(result, "New draft version created")
if not (result and result.get("Status")):
	return
newId = result.get("NewId")
self.refreshVersionList()
if not newId:
	return
self.view.custom.activeVersionId = newId
bundle = self._bundleFor(newId)
self.view.custom.state = {"selected": bundle, "editDraft": self._cloneBundle(bundle)}

draft = self.view.custom.state.editDraft or {}
routeId = draft.get("id")
if not routeId:
	BlueRidge.Common.Notify.toast("No draft selected", "Cannot publish: no draft route is currently active.", "warning")
	return
name = (draft.get("name") or "").strip()
if not name:
	BlueRidge.Common.Notify.toast("Name required", "Enter a route name before publishing.", "warning")
	return
steps = BlueRidge.Common.Util.extractQualifiedValues(draft.get("steps")) or []
if not steps:
	BlueRidge.Common.Notify.toast("At least one step required", "Add at least one step before publishing.", "warning")
	return
for s in steps:
	if not (s or {}).get("OperationTemplateId"):
		BlueRidge.Common.Notify.toast("Incomplete step", "Every step needs an operation template before publishing.", "warning")
		return
eff = (draft.get("effectiveFromDisplay") or "").strip() or None
result = BlueRidge.Parts.RouteTemplate.publishWithSave(routeId, name, eff, steps)
BlueRidge.Common.Ui.notifyResult(result, "Route published")
if result and result.get("Status"):
	self.refreshVersionList()
	self.loadActiveVersion()

draft = self.view.custom.state.editDraft or {}
draftId = draft.get("id")
draftVer = draft.get("versionNumber")
if not draftId:
	return
priorVer = None
for v in (self.view.custom.versions or []):
	if not v:
		continue
	if v.get("Id") == draftId:
		continue
	if v.get("PublishedAt") and not v.get("DeprecatedAt"):
		priorVer = v.get("VersionNumber")
		break
if priorVer is None:
	self.handlePublish()
	return
msg = "Publish v" + str(draftVer) + "? This will deprecate v" + str(priorVer) + " (currently active in production)."
system.perspective.openPopup(
	id="mpp-confirm-destructive",
	view="BlueRidge/Components/Popups/ConfirmDestructive",
	modal=True,
	showCloseIcon=False,
	params={
		"title":        "Publish Route",
		"message":      msg,
		"confirmLabel": "Publish",
		"cancelLabel":  "Cancel",
		"confirmClass": "btn btn-primary btn-sm",
		"replyMessage": "routeConfirmPublishResult",
	},
)

messageHandlers.script:
if not payload:
	return
if payload.get("action") != "confirm":
	return
self.handlePublish()

if not payload:
	return
if payload.get("action") != "confirm":
	return
sel = self.view.custom.state.selected or {}
routeId = sel.get("id")
if not routeId:
	return
result = BlueRidge.Parts.RouteTemplate.deprecate(routeId)
BlueRidge.Common.Ui.notifyResult(result, "Route deprecated")
if result and result.get("Status"):
	self.refreshVersionList()
	self.loadActiveVersion()

if not payload:
	return
if payload.get("action") != "confirm":
	return
draft = self.view.custom.state.editDraft or {}
routeId = draft.get("id")
if not routeId:
	return
result = BlueRidge.Parts.RouteTemplate.discardDraft(routeId)
BlueRidge.Common.Ui.notifyResult(result, "Draft discarded")
if result and result.get("Status"):
	self.view.custom.activeVersionId = None
	self.refreshVersionList()
	itemId = self.view.params.value
	defaultId = BlueRidge.Parts.RouteTemplate.getDefaultVersionId(itemId)
	if defaultId:
		self.view.custom.activeVersionId = defaultId
